SELECT COUNT(*)
FROM empproject
WHERE empid = #{empId}

    AND projectid = #{projectid}

AND UPPER(role) = 'M'

mapper.update:
UPDATE projectnotice
SET state = 0
WHERE projectNoticeNum = #{projectNoticeNum}

UPDATE projectnotice
SET hitcount = hitcount + 1
WHERE projectNoticeNum = #{projectNoticeNum}

mapper.select:
SELECT COUNT(*) FROM projectnotice n WHERE n.state = 1 AND EXISTS ( SELECT 1 FROM empproject ep WHERE ep.projectid = n.projectid AND ep.empid = #{empId} )
AND n.projectid = #{projectid}
AND ( n.subject LIKE '%' || #{keyword} || '%' OR n.content LIKE '%' || #{keyword} || '%' )
